import numpy as np

def prepare_bb84_state(bit, basis):
    """
    Prepare a BB84 state.
    """
    if basis == 'Z':
        if bit == 0:
            return np.array([1, 0], dtype=complex)  # |0⟩
        else:
            return np.array([0, 1], dtype=complex)  # |1⟩
    elif basis == 'X':
        if bit == 0:
            return np.array([1, 1], dtype=complex) / np.sqrt(2)  # |+⟩
        else:
            return np.array([1, -1], dtype=complex) / np.sqrt(2)  # |-⟩
    else:
        raise ValueError(f"Invalid basis: {basis}")

# Test all four cases
test_cases = [(0, 'Z'), (1, 'Z'), (0, 'X'), (1, 'X')]
print("BB84 State Preparation:")
print("=" * 40)
for bit, basis in test_cases:
    state = prepare_bb84_state(bit, basis)
    print(f"Bit {bit}, Basis {basis}: {np.round(state, 3)}")
